import React, { useState } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { useTheme } from '../contexts/ThemeContext';
import { LogOut, Shield, Monitor, MapPin } from 'lucide-react';
import { Button } from '../components/ui/button';
import ThemeToggle from '../components/ThemeToggle';
import PortalSwitcher from '../components/PortalSwitcher';
import CustomerPortalContent from '../components/CustomerPortalContent';
import toast from 'react-hot-toast';

const CustomerPortal = () => {
  const { user, logout } = useAuth();
  const { theme } = useTheme();

  const [activeTab, setActiveTab] = useState('dashboard');

  const handleLogout = () => {
    logout();
    toast.success('Erfolgreich abgemeldet');
  };

  return (
    <div className={`min-h-screen ${theme === 'dark' ? 'bg-[#1a1a1a]' : 'bg-gray-50'}`}>
      {/* Header */}
      <header className={`shadow-sm ${theme === 'dark' ? 'bg-[#2a2a2a]' : 'bg-white'}`}>
        {/* Top Header Bar */}
        <div className={`border-b ${theme === 'dark' ? 'border-gray-800' : 'border-gray-200'}`}>
          <div className="px-4 sm:px-6 lg:px-8">
            <div className="flex justify-between items-center h-16">
              {/* Left Side: Logo & Title */}
              <div 
                className="flex items-center space-x-3 cursor-pointer hover:opacity-80 transition-opacity"
                onClick={() => {
                  // Navigate to dashboard
                  setActiveTab('dashboard');
                  window.location.hash = '#dashboard';
                }}
              >
                <Shield className={`h-8 w-8 ${theme === 'dark' ? 'text-[#c00000]' : 'text-[#c00000]'}`} />
                <div>
                  <h1 className={`text-xl font-bold ${theme === 'dark' ? 'text-white' : 'text-[#c00000]'}`}>TSRID Kunden Portal</h1>
                  <p className={`text-xs ${theme === 'dark' ? 'text-gray-400' : 'text-gray-500'}`}>{user?.company}</p>
                </div>
              </div>
              
              {/* Right Side: Portal Switcher, User Info, Theme Toggle, Logout */}
              <div className="flex items-center space-x-4">
                <PortalSwitcher />
                <div className="text-right">
                  <p className={`text-sm font-medium ${theme === 'dark' ? 'text-white' : 'text-gray-900'}`}>{user?.name}</p>
                  <p className={`text-xs ${theme === 'dark' ? 'text-gray-400' : 'text-gray-500'}`}>Kunde</p>
                </div>
                <ThemeToggle />
                <Button
                  variant="outline"
                  size="sm"
                  onClick={handleLogout}
                  className={`flex items-center space-x-2 ${
                    theme === 'dark' 
                      ? 'border-[#c00000] text-white hover:bg-[#c00000]' 
                      : 'border-[#c00000] text-[#c00000] hover:bg-[#c00000] hover:text-white'
                  }`}
                >
                  <LogOut className="h-4 w-4" />
                  <span>Abmelden</span>
                </Button>
              </div>
            </div>
          </div>
        </div>
        
        {/* Navigation Tabs - Full Width */}
        <div className={`border-b ${theme === 'dark' ? 'bg-[#2d2d2d] border-gray-700' : 'bg-white border-gray-200'}`}>
          <div className="px-4 sm:px-6 lg:px-8">
            <nav className="flex space-x-8">
              {[
                { id: 'dashboard', label: 'Dashboard', icon: Monitor },
                { id: 'devices', label: 'Geräte', icon: Monitor },
                { id: 'locations', label: 'Standorte', icon: MapPin }
              ].map((tab) => (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id)}
                  className={`flex items-center space-x-2 py-4 px-1 border-b-2 font-medium text-sm transition-colors ${
                    activeTab === tab.id
                      ? 'border-[#c00000] text-[#c00000]'
                      : theme === 'dark'
                      ? 'border-transparent text-gray-400 hover:text-gray-300 hover:border-gray-600'
                      : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                  }`}
                >
                  <tab.icon className="h-4 w-4" />
                  <span>{tab.label}</span>
                </button>
              ))}
            </nav>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="w-full px-4 sm:px-6 lg:px-8 py-8">
        <CustomerPortalContent 
          isImpersonation={false} 
          activeTab={activeTab}
          setActiveTab={setActiveTab}
        />
      </main>
    </div>
  );
};

export default CustomerPortal;

 
